def minPath(grid, k):
    from heapq import heappush, heappop
    N = len(grid)
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
    min_path = None

    def is_valid(x, y):
        return 0 <= x < N and 0 <= y < N

    for start_x in range(N):
        for start_y in range(N):
            pq = [(grid[start_x][start_y], [(start_x, start_y)])]
            while pq:
                current_value, path = heappop(pq)
                if len(path) == k:
                    current_path_values = [grid[x][y] for x, y in path]
                    if min_path is None or current_path_values < min_path:
                        min_path = current_path_values
                    continue
                last_x, last_y = path[-1]
                for dx, dy in directions:
                    new_x, new_y = last_x + dx, last_y + dy
                    if is_valid(new_x, new_y) and (new_x, new_y) not in path:
                        new_path = path + [(new_x, new_y)]
                        new_value = current_value + grid[new_x][new_y]
                        heappush(pq, (new_value, new_path))

    return min_path

